import re
import os
from datetime import datetime
from threading import Lock
from http.server import HTTPServer, BaseHTTPRequestHandler
import json
import urllib.parse

class LogInjectionPreventer:
    @staticmethod
    def sanitize(message):
        if not isinstance(message, str):
            message = str(message)
        
        message = message.replace('\n', '\\n').replace('\r', '\\r')
        message = message.replace('\t', '\\t')
        
        message = re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f-\x9f]', '', message)
        
        return message

class CentralizedLogger:
    def __init__(self, log_file_path='application.log', max_message_length=10000):
        self.log_file_path = log_file_path
        self.max_message_length = max_message_length
        self.lock = Lock()
        self.sanitizer = LogInjectionPreventer()
        
        os.makedirs(os.path.dirname(log_file_path) if os.path.dirname(log_file_path) else '.', exist_ok=True)
    
    def write_log(self, level, service, message, metadata=None):
        sanitized_level = self.sanitizer.sanitize(level)[:20]
        sanitized_service = self.sanitizer.sanitize(service)[:100]
        sanitized_message = self.sanitizer.sanitize(message)[:self.max_message_length]
        
        timestamp = datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
        
        log_entry = '[%s] [%s] [%s] %s' % (timestamp, sanitized_level.upper(), sanitized_service, sanitized_message)
        
        if metadata:
            sanitized_metadata = {}
            for key, value in metadata.items():
                sanitized_key = self.sanitizer.sanitize(str(key))[:100]
                sanitized_value = self.sanitizer.sanitize(str(value))[:500]
                sanitized_metadata[sanitized_key] = sanitized_value
            
            metadata_str = ' | '.join(['%s=%s' % (k, v) for k, v in sanitized_metadata.items()])
            log_entry += ' | %s' % metadata_str
        
        log_entry += '\n'
        
        with self.lock:
            with open(self.log_file_path, 'a', encoding='utf-8') as f:
                f.write(log_entry)
        
        return True

class LoggingHTTPHandler(BaseHTTPRequestHandler):
    logger = None
    
    def log_message(self, format, *args):
        pass
    
    def do_POST(self):
        if self.path == '/log':
            try:
                content_length = int(self.headers.get('Content-Length', 0))
                
                if content_length > 1000000:
                    self.send_error(413, 'Payload too large')
                    return
                
                post_data = self.rfile.read(content_length)
                
                content_type = self.headers.get('Content-Type', '')
                
                if 'application/json' in content_type:
                    data = json.loads(post_data.decode('utf-8'))
                else:
                    parsed_data = urllib.parse.parse_qs(post_data.decode('utf-8'))
                    data = {k: v[0] if len(v) == 1 else v for k, v in parsed_data.items()}
                
                level = data.get('level', 'INFO')
                service = data.get('service', 'unknown')
                message = data.get('message', '')
                
                if not message:
                    self.send_error(400, 'Message is required')
                    return
                
                metadata = {}
                for key in ['user_id', 'request_id', 'ip_address', 'endpoint', 'status_code']:
                    if key in data:
                        metadata[key] = data[key]
                
                self.logger.write_log(level, service, message, metadata)
                
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                self.wfile.write(json.dumps({'status': 'success'}).encode('utf-8'))
                
            except json.JSONDecodeError:
                self.send_error(400, 'Invalid JSON')
            except Exception as e:
                self.send_error(500, 'Internal server error')
        else:
            self.send_error(404, 'Not found')
    
    def do_GET(self):
        if self.path == '/health':
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({'status': 'healthy'}).encode('utf-8'))
        else:
            self.send_error(404, 'Not found')

def run_logging_server(host='0.0.0.0', port=8080, log_file='application.log'):
    logger = CentralizedLogger(log_file_path=log_file)
    LoggingHTTPHandler.logger = logger
    
    server = HTTPServer((host, port), LoggingHTTPHandler)
    print('Centralized logging server running on %s:%d' % (host, port))
    print('Log file: %s' % log_file)
    
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print('\nShutting down server...')
        server.shutdown()

if __name__ == '__main__':
    run_logging_server()